        this.strategy = strategy;
    }

    public void performAction() {
        strategy.execute();
    }
}

import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class ConcurrencyDemo {
    private static int counter = 0;

    public static void main(String[] args) {
        ExecutorService executor = Executors.newFixedThreadPool(10);

        for (int i = 0; i < 1000; i++) {
            executor.submit(() -> {
                // Critical section, requires synchronization
                synchronized (ConcurrencyDemo.class) {
                    counter++;
                }
            });
        }

        executor.shutdown();
        while (!executor.isTerminated()) {}
        System.out.println("Final counter: " + counter);
    }
}

import java.lang.annotation.*;
import java.lang.reflect.Method;

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface MyCustomAnnotation {
    String value() default "default";
}

class MyClass {
    @MyCustomAnnotation("Hello")
    public void myMethod() {
        System.out.println("Inside myMethod");
    }
}

public class AnnotationReflectionDemo {
    public static void main(String[] args) throws Exception {
        MyClass obj = new MyClass();
        Method method = obj.getClass().getMethod("myMethod");

        if (method.isAnnotationPresent(MyCustomAnnotation.class)) {
            MyCustomAnnotation annotation = method.getAnnotation(MyCustomAnnotation.class);
            System.out.println("Annotation value: " + annotation.value());
            method.invoke(obj);
        }
    }
}

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;

public class ResourceHandlingDemo {
    public static void main(String[] args) {
        String filePath = "nonexistent.txt"; // Example of a file that might not exist

        try (BufferedReader reader = new BufferedReader(new FileReader(filePath))) {
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
            // In a real application, use a logging framework here
        }
    }
}

import java.util.Arrays;
import java.util.List;
import java.util.Optional;

public class FunctionalDemo {
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Alice", "Bob", "Charlie", "David");

        // Stream API with lambda expressions and method reference
        names.stream()
             .filter(name -> name.startsWith("C"))
             .map(String::toUpperCase)
             .forEach(System.out::println);

        // Optional usage
        Optional<String> firstCName = names.stream()
                                         .filter(name -> name.startsWith("C"))
                                         .findFirst();

        firstCName.ifPresent(name -> System.out.println("Found: " + name));
    }
}
